## If you need a synchronous API (no async allowed)

```csharp
public class EventProcessor
{
    private readonly Channel<string> _channel = Channel.CreateUnbounded<string>();
    private Thread? _thread;
    private CancellationTokenSource? _cts;

    public void Start()
    {
        _cts = new CancellationTokenSource();
        _thread = new Thread(RunLoop);
        _thread.Start();
    }

    private void RunLoop()
    {
        var token = _cts!.Token;
        var reader = _channel.Reader;
        try
        {
            while (reader.WaitToReadAsync(token).AsTask().GetAwaiter().GetResult())
            {
                while (reader.TryRead(out var item))
                {
                    token.ThrowIfCancellationRequested();
                    Handle(item);
                }
            }
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Graceful shutdown
        }
    }

    public void Enqueue(string item) => _channel.Writer.TryWrite(item);

    public void Stop()
    {
        _channel.Writer.Complete();
        if (!_thread!.Join(5000))
        {
            _cts!.Cancel(); // Force cancellation after timeout
            _thread.Join();
        }
        _cts?.Dispose();
    }

    private void Handle(string item) { /* ... */ }
}
```

